import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicAdobecodebanc() {
        // Shortest window in "ADOBECODEBANC" containing A, B, C is "BANC"
        assertEquals("BANC", new Solution().minWindow("ADOBECODEBANC", "ABC"));
    }

    @Test
    void singleCharMatch() {
        // s and t are the same single character
        assertEquals("a", new Solution().minWindow("a", "a"));
    }

    @Test
    void insufficientDuplicates() {
        // t needs two 'a's but s has only one
        assertEquals("", new Solution().minWindow("a", "aa"));
    }

    @Test
    void emptyS() {
        // Empty s — no window possible
        assertEquals("", new Solution().minWindow("", "abc"));
    }

    @Test
    void charAbsentFromS() {
        // t contains a char that never appears in s
        assertEquals("", new Solution().minWindow("aa", "b"));
    }

    @Test
    void windowWithDuplicateNeeds() {
        // t="aab": need two a's and one b. s="aaab" → window "aab" (indices 1-3, length 3)
        assertEquals("aab", new Solution().minWindow("aaab", "aab"));
    }

    @Test
    void wholeStringIsMinWindow() {
        // Every char in t appears exactly once in s at required positions
        assertEquals("abc", new Solution().minWindow("abc", "abc"));
    }
}
